import React, { useEffect, useState, useRef } from "react";
import { useParams, Link } from "react-router-dom";
import axios from "axios";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000";

export default function RoomDetails() {
  const { id } = useParams();

  const [room, setRoom] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const [index, setIndex] = useState(0);
  const galleryRef = useRef(null);

  /* ---------------- FETCH ROOM ---------------- */
  useEffect(() => {
    fetchRoom();
  }, [id]);

  async function fetchRoom() {
    try {
      const res = await axios.get(`${API_BASE}/api/rooms/${id}/`);
      setRoom(res.data);
    } catch (err) {
      console.error(err);
      setError("Room not found");
    } finally {
      setLoading(false);
    }
  }

  /* ---------------- GALLERY ---------------- */
  const moveGallery = (dir) => {
    if (!galleryRef.current) return;
    const total = galleryRef.current.children.length;
    if (!total) return;
    setIndex((prev) => (prev + dir + total) % total);
  };

  /* ---------------- ANIMATIONS ---------------- */
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            if (entry.target.classList.contains("amenity")) {
              const siblings = [...entry.target.parentNode.children];
              const delay = siblings.indexOf(entry.target) * 150;
              setTimeout(() => entry.target.classList.add("show"), delay);
            } else {
              entry.target.classList.add("show");
            }
          }
        });
      },
      { threshold: 0.1 }
    );

    document
      .querySelectorAll(".fade-in, .fade-up, .fade-left, .fade-right, .amenity")
      .forEach((el) => observer.observe(el));

    return () => observer.disconnect();
  }, []);

  if (loading) return <p style={{ padding: 40 }}>Loading...</p>;
  if (error) return <p style={{ padding: 40 }}>{error}</p>;

  /* ---------------- IMAGE ---------------- */
  const image =
    room?.image
      ? room.image.startsWith("http")
        ? room.image
        : `${API_BASE}${room.image}`
      : "/assets/images/room_blur.png";

  return (
    <>
      {/* NAV */}
      <header className="nav fade-in">
        <div className="nav-inner">
          <div className="brand">
            <img
              src="/assets/images/glamp_logo.png"
              alt="Glamp Resort Logo"
              className="logo"
            />
          </div>
          <nav className="menu">
            <Link to="/">Home</Link>
            <a href="#">Rooms</a>
            <Link to="/reservation">Reservation</Link>
            <a href="#">Pages</a>
            <a href="#">News</a>
            <a href="#">Contact</a>
            <Link className="reserve" to="/reservation">
              Reserve
            </Link>
          </nav>
        </div>
      </header>

      {/* HERO */}
      <section
        className="hero fade-up"
        style={{
          background: `url("${image}") center/cover no-repeat`,
        }}
      >
        <div className="hero-overlay">
          <h1 className="fade-in">{room.room_name}</h1>
          <p className="fade-up">
            Experience nature with unmatched comfort & elegance
          </p>
          <div className="breadcrumb fade-right">
            <Link to="/">Home</Link> / Room Details
          </div>
        </div>
      </section>

      {/* DETAILS */}
      <section className="room-details fade-up">
        <div className="room-container">
          <h2 className="room-title fade-in">{room.room_name}</h2>

          <div className="room-price-box fade-up">
            <div className="price">
              ₹{Number(room.price).toFixed(2)} / night
            </div>
            <Link to="/reservation" className="reserve-btn">
              RESERVE NOW
            </Link>
          </div>

          <p className="room-description fade-left">
            {room.description}
          </p>

          {/* GALLERY (uses same image safely) */}
          <div className="room-gallery fade-up">
            <div
              className="gallery-wrapper"
              ref={galleryRef}
              style={{ transform: `translateX(-${index * 100}%)` }}
            >
              <img src={image} alt="Room" />
            </div>

            <button
              className="gallery-btn left"
              onClick={() => moveGallery(-1)}
            >
              ‹
            </button>
            <button
              className="gallery-btn right"
              onClick={() => moveGallery(1)}
            >
              ›
            </button>
          </div>
        </div>
      </section>

      {/* AMENITIES */}
      <section className="room-amenities fade-up">
        <div className="amenities-container">
          {[
            ["fa-users", "4 Guests"],
            ["fa-arrows-alt", "35 Feet Size"],
            ["fa-door-open", "Connecting Rooms"],
            ["fa-bed", "1 King Bed"],
            ["fa-tv", "Cable TV"],
            ["fa-shower", "Shower"],
            ["fa-chair", "Work Desk"],
            ["fa-bath", "Bathtub"],
            ["fa-lock", "Safebox"],
            ["fa-wifi", "Free WiFi"],
            ["fa-archway", "Balcony"],
            ["fa-city", "City View"],
          ].map(([icon, text]) => (
            <div className="amenity" key={text}>
              <i className={`fas ${icon}`}></i> <span>{text}</span>
            </div>
          ))}
        </div>
      </section>

      {/* FOOTER */}
      <footer className="footer fade-in">
        <div className="footer-inner">
          <div className="footer-col fade-left">
            <h4>Address</h4>
            <p>Adimali, Idukki, Kerala</p>
          </div>
          <div className="footer-col logo-col fade-up">
            <h2 className="footer-logo">THE PARADISE GLAMP</h2>
            <div className="stars">★★★★★</div>
          </div>
          <div className="footer-col fade-right">
            <h4>Contact Us</h4>
            <p>+91 9497185771</p>
            <p>theparadiseglamp@gmail.com</p>
          </div>
        </div>
      </footer>
    </>
  );
}
